import chalk from 'chalk';
import { writeFileSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import { createSqliteStorage } from '@flusk/resources';
import { formatDataset } from '@flusk/business-logic';
import type { ExportFormat } from '@flusk/business-logic';

// --- BEGIN CUSTOM ---
interface ExportOpts {
  name: string;
  format: string;
  output: string;
}

export function trainingExportAction(opts: ExportOpts): void {
  const storage = createSqliteStorage();
  const format = opts.format as ExportFormat;
  const pairs = storage.trainingPairs.list(10000, 0);

  if (pairs.length === 0) {
    console.log(chalk.dim('No training pairs to export.'));
    return;
  }

  const pairInputs = pairs.map(p => ({
    prompt: p.prompt,
    completion: p.completion,
    systemPrompt: p.systemPrompt,
  }));

  const content = formatDataset(pairInputs, format);
  mkdirSync(opts.output, { recursive: true });
  const filePath = join(opts.output, `${opts.name}.${format}`);
  writeFileSync(filePath, content, 'utf-8');

  console.log(chalk.green(`\n✅ Exported ${pairs.length} pairs → ${filePath}\n`));
}
// --- END CUSTOM ---
